import Link from 'next/link';
import { 
  ArrowRight, 
  CheckCircle2, 
  ShieldCheck, 
  Lock, 
  Smartphone, 
  Waves, 
  Wrench, 
  Shield, 
  TreePine, 
  Bug, 
  Droplets 
} from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Card, CardContent } from '@/components/ui/card';

export default function LandingPage() {
  return (
    <div className="flex flex-col min-h-screen">
      {/* NAVBAR */}
      <nav className="sticky top-0 z-50 w-full bg-[var(--surface-dark)]/90 backdrop-blur-md border-b border-white/10 px-6 h-16 flex items-center justify-between">
        <div className="flex items-center gap-10">
          <Link href="/" className="font-display text-2xl text-[var(--brand-primary)]">
            Oweru
          </Link>
          <div className="hidden md:flex items-center gap-8 text-[var(--text-on-dark)]/70 text-sm font-medium">
            <Link href="#features" className="hover:text-[var(--brand-primary)] transition-colors">Features</Link>
            <Link href="#how-it-works" className="hover:text-[var(--brand-primary)] transition-colors">How it Works</Link>
            <Link href="#services" className="hover:text-[var(--brand-primary)] transition-colors">Services</Link>
          </div>
        </div>
        <div className="flex items-center gap-4">
          <Link href="/login" className="text-[var(--text-on-dark)] text-sm font-medium hover:text-[var(--brand-primary)]">
            Login
          </Link>
          <Button variant="default" className="bg-[var(--brand-primary)] hover:bg-[var(--brand-primary-dim)] rounded-full px-6 text-sm">
            Get Started <ArrowRight className="ml-2 w-4 h-4" />
          </Button>
        </div>
      </nav>

      {/* HERO SECTION */}
      <section className="relative min-h-[90vh] flex items-center justify-center bg-[var(--surface-dark)] pt-20 overflow-hidden">
        <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,var(--brand-primary),transparent)] opacity-10 blur-[120px]" />
        <div className="container mx-auto px-6 text-center z-10">
          <span className="text-[var(--brand-primary)] text-xs font-semibold tracking-[0.12em] uppercase mb-6 block animate-fadeIn">
            Tanzania's Property Platform
          </span>
          <h1 className="font-display text-[clamp(36px,8vw,64px)] leading-[1.1] text-[var(--text-on-dark)] mb-8 max-w-4xl mx-auto tracking-tight">
            Your Properties, Professionally Managed.
          </h1>
          <p className="text-[var(--text-on-dark)]/60 text-lg md:text-xl max-w-2xl mx-auto mb-12 leading-relaxed">
            The all-in-one orchestrator for premium property services. Vetted professionals, rule-based pricing, and zero management headache.
          </p>
          <div className="flex flex-col sm:flex-row items-center justify-center gap-4 mb-16">
            <Button size="lg" className="bg-[var(--brand-primary)] hover:bg-[var(--brand-primary-dim)] rounded-full px-8 h-14 text-base">
              Register as Owner
            </Button>
            <Button size="lg" variant="outline" className="border-white/20 text-[var(--text-on-dark)] hover:bg-white/5 rounded-full px-8 h-14 text-base">
              I'm a Provider <ArrowRight className="ml-2 w-4 h-4" />
            </Button>
          </div>
          
          <div className="grid grid-cols-1 md:grid-cols-3 gap-8 max-w-4xl mx-auto text-[var(--text-on-dark)]/80">
            {[
              { icon: ShieldCheck, text: "Vetted Providers" },
              { icon: Lock, text: "Price-Locked Quotes" },
              { icon: Smartphone, text: "Mobile Money Payouts" }
            ].map((item, i) => (
              <div key={i} className="flex items-center justify-center gap-3 py-4 px-6 rounded-2xl bg-white/5 border border-white/10">
                <item.icon className="text-[var(--brand-primary)] w-5 h-5" />
                <span className="text-sm font-medium">{item.text}</span>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* HOW IT WORKS */}
      <section id="how-it-works" className="py-24 bg-[var(--surface-overlay)]">
        <div className="container mx-auto px-6">
          <div className="text-center mb-16">
            <h2 className="font-display text-4xl mb-4">How Oweru Works</h2>
            <p className="text-[var(--text-secondary)]">Streamlined orchestration for effortless property care.</p>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
            {[
              { 
                num: "01", 
                title: "Register & List", 
                desc: "Property owners onboard their buildings and units, selecting from our curated service catalog." 
              },
              { 
                num: "02", 
                title: "AI-Powered Matching", 
                desc: "Oweru's pricing engine provides instant quotes while our algorithm identifies the best vetted provider." 
              },
              { 
                num: "03", 
                title: "Professional Delivery", 
                desc: "Providers execute tasks with GPS-verified check-ins and evidence submission. You pay only when verified." 
              }
            ].map((step, i) => (
              <Card key={i} className="bg-[var(--surface-dark-card)] border-white/10 text-[var(--text-on-dark)] p-8 rounded-[var(--radius-lg)]">
                <span className="font-display text-6xl text-[var(--brand-primary)]/20 mb-6 block tracking-tighter">
                  {step.num}
                </span>
                <h3 className="text-xl font-semibold mb-4">{step.title}</h3>
                <p className="text-[var(--text-on-dark)]/50 leading-relaxed">{step.desc}</p>
              </Card>
            ))}
          </div>
        </div>
      </section>

      {/* SERVICES GRID */}
      <section id="services" className="py-24 bg-[var(--surface-page)]">
        <div className="container mx-auto px-6">
          <div className="flex flex-col md:flex-row md:items-end justify-between mb-16 gap-6">
            <div className="max-w-xl">
              <h2 className="font-display text-4xl mb-4">Comprehensive Care</h2>
              <p className="text-[var(--text-secondary)]">From routine maintenance to high-security solutions, Oweru handles every aspect of your property's operational needs.</p>
            </div>
            <Button variant="outline" className="rounded-full border-[var(--border-default)]">
              View Catalog
            </Button>
          </div>
          <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-6 gap-4">
            {[
              { icon: Waves, label: "Cleaning" },
              { icon: Wrench, label: "Maintenance" },
              { icon: Shield, label: "Security" },
              { icon: TreePine, label: "Landscaping" },
              { icon: Bug, label: "Pest Control" },
              { icon: Droplets, label: "Plumbing" },
            ].map((service, i) => (
              <div key={i} className="group p-6 bg-white border border-[var(--border-subtle)] rounded-[var(--radius-lg)] hover:border-[var(--brand-primary)] transition-all cursor-pointer text-center">
                <div className="w-12 h-12 rounded-full bg-[var(--surface-overlay)] flex items-center justify-center mx-auto mb-4 group-hover:bg-[var(--brand-primary)]/10 transition-colors">
                  <service.icon className="w-6 h-6 text-[var(--text-secondary)] group-hover:text-[var(--brand-primary)]" />
                </div>
                <span className="text-sm font-medium text-[var(--text-primary)]">{service.label}</span>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* TRUST SECTION */}
      <section className="py-24 border-t border-[var(--border-subtle)]">
        <div className="container mx-auto px-6 text-center">
          <h2 className="font-display text-4xl mb-16">The Oweru Guarantee</h2>
          <div className="grid grid-cols-1 md:grid-cols-3 gap-12 max-w-5xl mx-auto">
            {[
              {
                title: "Absolute Privacy",
                desc: "Owner and provider identities are isolated. We handle the communication so you don't have to."
              },
              {
                title: "Financial Integrity",
                desc: "80/20 revenue split with atomic transactions. Your money moves only when work is verified."
              },
              {
                title: "Quality or Refund",
                desc: "Dispute any task within 24 hours. Our staff reviews evidence to ensure fairness for all."
              }
            ].map((item, i) => (
              <div key={i} className="flex flex-col items-center">
                <div className="mb-6 p-4 rounded-full bg-[var(--state-warning-bg)]">
                  <ShieldCheck className="w-8 h-8 text-[var(--brand-gold)]" />
                </div>
                <h3 className="text-xl font-semibold mb-3">{item.title}</h3>
                <p className="text-[var(--text-secondary)] text-sm leading-relaxed">{item.desc}</p>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* CTA SECTION */}
      <section className="py-24">
        <div className="container mx-auto px-6">
          <div className="bg-[var(--brand-primary)] rounded-[var(--radius-xl)] p-12 md:p-20 text-center text-white relative overflow-hidden">
            <div className="absolute top-0 right-0 w-64 h-64 bg-white/10 rounded-full blur-3xl -mr-32 -mt-32" />
            <div className="relative z-10">
              <h2 className="font-display text-4xl md:text-5xl mb-8 max-w-2xl mx-auto leading-tight">
                Ready to stop managing and start owning?
              </h2>
              <div className="flex flex-col sm:flex-row items-center justify-center gap-4 max-w-lg mx-auto">
                <input 
                  type="email" 
                  placeholder="Enter your email"
                  className="w-full h-14 px-6 rounded-full bg-white text-[var(--text-primary)] outline-none focus:ring-2 focus:ring-white/20 transition-all"
                />
                <Button size="lg" className="bg-[var(--surface-dark)] hover:bg-black rounded-full px-8 h-14 min-w-fit">
                  Get Started
                </Button>
              </div>
            </div>
          </div>
        </div>
      </section>

      {/* FOOTER */}
      <footer className="bg-[var(--surface-dark)] py-16 text-[var(--text-on-dark)]/50">
        <div className="container mx-auto px-6">
          <div className="grid grid-cols-2 md:grid-cols-4 gap-12 mb-16">
            <div className="col-span-2">
              <Link href="/" className="font-display text-2xl text-[var(--brand-primary)] mb-6 block">
                Oweru
              </Link>
              <p className="max-w-xs text-sm leading-relaxed">
                The professional management layer for high-trust property services in Tanzania and beyond.
              </p>
            </div>
            <div>
              <h4 className="text-[var(--text-on-dark)] font-semibold mb-6">Platform</h4>
              <ul className="space-y-4 text-sm">
                <li><Link href="#" className="hover:text-white transition-colors">Property Onboarding</Link></li>
                <li><Link href="#" className="hover:text-white transition-colors">Service Catalog</Link></li>
                <li><Link href="#" className="hover:text-white transition-colors">Pricing Engine</Link></li>
              </ul>
            </div>
            <div>
              <h4 className="text-[var(--text-on-dark)] font-semibold mb-6">Legal</h4>
              <ul className="space-y-4 text-sm">
                <li><Link href="#" className="hover:text-white transition-colors">Privacy Policy</Link></li>
                <li><Link href="#" className="hover:text-white transition-colors">Terms of Service</Link></li>
                <li><Link href="#" className="hover:text-white transition-colors">Provider Contract</Link></li>
              </ul>
            </div>
          </div>
          <div className="pt-8 border-t border-white/5 flex flex-col md:flex-row justify-between items-center gap-6 text-xs uppercase tracking-widest">
            <p>© 2025 Oweru Company Limited. All rights reserved.</p>
            <div className="flex gap-8">
              <Link href="#" className="hover:text-white transition-colors">Twitter</Link>
              <Link href="#" className="hover:text-white transition-colors">LinkedIn</Link>
            </div>
          </div>
        </div>
      </footer>
    </div>
  );
}